mapper.select:
SELECT id, post_id, user_id, created_at
FROM social_like
WHERE post_id = #{postId} AND user_id = #{userId}

mapper.update:
UPDATE social_post
SET like_count = CASE WHEN like_count > 0 THEN like_count - 1 ELSE 0 END
WHERE id = #{postId}

mapper.select:
SELECT nickname
FROM sys_user
WHERE id = #{userId}
